          <div className="flex flex-col justify-center items-start xl:w-[386px] w-full xl:mb-0 mb-[16px] relative gap-1">
            <p className="text-lg italic text-[#617a8b] font-sofiaSans">{t('select_region')}</p>
            <Select
              options={data.items.map((item: any) => ({ value: item.region, label: item.title }))}
              value={activeLocation}
              onChange={(value) => setActiveLocation(value as string)}
              variant="secondary"
            />
          </div>
